import { describe, expect, test } from '@a0n/gnosis/test';
import { readFile } from 'node:fs/promises';
import { resolve } from 'node:path';

import { synthesizeAeonFluxSiteWitnessesFromSource } from './aeon-flux-site-witness';

describe('Aeon Flux site witness synthesis', () => {
  test('synthesizes a tight zero-deficit witness from WallingtonRotation source', () => {
    const witnesses = synthesizeAeonFluxSiteWitnessesFromSource(`
(prompt: FlowFrame { role: 'prompt-sequence' })
(rotated_output: WallingtonRotation { stages: '4', chunks: '4', stageNames: '[embed,attend,ffn,project]' })
(prompt)-[:PROCESS]->(rotated_output)
`);

    expect(witnesses).toHaveLength(1);
    const [witness] = witnesses;
    expect(witness).toBeDefined();
    expect(witness?.primitiveId).toBe('rotated_output');
    expect(witness?.pathCount).toBe(4);
    expect(witness?.streamCount).toBe(4);
    expect(witness?.deficit).toBe(0);
    expect(witness?.chunkNodeIds).toEqual([
      'rotated_output__chunk_0',
      'rotated_output__chunk_1',
      'rotated_output__chunk_2',
      'rotated_output__chunk_3',
    ]);
    expect(witness?.stageNodeIds).toEqual([
      'embed',
      'attend',
      'ffn',
      'project',
    ]);
    expect(witness?.regime).toBe('tight_lossless_transport_exists');
    expect(witness?.theoremRef).toBe(
      'aeon_flux_site_zero_deficit_iff_tight_lossless_transport'
    );
  });

  test('reads the checked-in transformer example as a zero-deficit Aeon Flux site', async () => {
    const examplePath = resolve(
      __dirname,
      '../examples/transformer/wallington-rotation.gg'
    );
    const source = await readFile(examplePath, 'utf8');
    const witnesses = synthesizeAeonFluxSiteWitnessesFromSource(source);

    expect(witnesses).toHaveLength(1);
    const [witness] = witnesses;
    expect(witness?.primitive).toBe('WallingtonRotation');
    expect(witness?.pathCount).toBe(4);
    expect(witness?.streamCount).toBe(4);
    expect(witness?.regime).toBe('tight_lossless_transport_exists');
  });
});
